 41→    func start() {
 42→        guard Purchases.isConfigured else {
 43→            setError("RevenueCat is not configured.")
 44→            return
 45→        }
 46→
 47→        if customerInfoStreamTask == nil {
 48→            customerInfoStreamTask = Task {
 49→                for await updatedInfo in Purchases.shared.customerInfoStream {
 50→                    await MainActor.run {
 51→                        self.apply(customerInfo: updatedInfo)
 52→                    }
 53→                }
 54→            }
 55→        }
 56→
 57→        Task {
 58→            await ensureStableSandboxAppUserIDIfNeeded()
 59→            await refreshAll()
 60→        }
 61→    }
