 68→    func refreshOfferings() async {
 69→        guard Purchases.isConfigured else { return }
 70→
 71→        isLoadingOfferings = true
 72→        defer { isLoadingOfferings = false }
 73→
 74→        do {
 75→            let offerings = try await Purchases.shared.offerings()
 76→            currentOffering = offerings.current ?? offerings["default"]
 77→
 78→            guard currentOffering != nil else {
 79→                setError("No active offering found. Set a current offering in RevenueCat and add monthly/yearly packages.")
 80→                return
 81→            }
 82→
 83→            if monthlyPackage == nil, yearlyPackage == nil {
 84→                setError("Offering loaded, but no monthly/yearly packages were detected.")
 85→                return
 86→            }
 87→
 88→            clearError()
 89→        } catch {
 90→            currentOffering = nil
 91→            setError("Could not load offerings: \(error.localizedDescription)")
 92→        }
 93→    }
 94→
 95→    func refreshCustomerInfo() async {
 96→        guard Purchases.isConfigured else { return }
 97→
 98→        isLoadingCustomerInfo = true
 99→        defer {
100→            isLoadingCustomerInfo = false
101→            hasLoadedAtLeastOnce = true
102→        }
103→
104→        do {
105→            let info = try await Purchases.shared.customerInfo()
106→            await MainActor.run {
107→                apply(customerInfo: info)
108→            }
109→            clearError()
110→        } catch {
111→            setError("Could not refresh subscription status: \(error.localizedDescription)")
112→        }
113→    }
