115→    func purchase(package: Package) async -> SubscriptionActionResult {
116→        guard Purchases.isConfigured else {
117→            let message = "RevenueCat is not configured."
118→            setError(message)
119→            return .failure(message)
120→        }
121→
122→        guard beginPurchase() else {
123→            return .failure("Purchase already in progress. Please wait.")
124→        }
125→        defer { endPurchase() }
126→
127→        do {
128→            let result = try await Purchases.shared.purchase(package: package)
129→            await MainActor.run {
130→                apply(customerInfo: result.customerInfo)
131→            }
132→
133→            if result.userCancelled {
134→                return .cancelled
135→            }
136→
137→            clearError()
138→            return .success
139→        } catch ErrorCode.purchaseCancelledError {
140→            return .cancelled
141→        } catch {
142→            let message = "Purchase failed: \(error.localizedDescription)"
143→            setError(message)
144→            return .failure(message)
145→        }
146→    }
