148→    func purchaseMonthly() async -> SubscriptionActionResult {
149→        guard let monthlyPackage else {
150→            let message = "Monthly package not found in the current offering."
151→            setError(message)
152→            return .failure(message)
153→        }
154→
155→        return await purchase(package: monthlyPackage)
156→    }
