158→    func purchaseYearly() async -> SubscriptionActionResult {
159→        guard let yearlyPackage else {
160→            let message = "Yearly package not found in the current offering."
161→            setError(message)
162→            return .failure(message)
163→        }
164→
165→        return await purchase(package: yearlyPackage)
166→    }
