214→    var monthlyPackage: Package? {
215→        guard let offering = currentOffering else { return nil }
216→        return offering.package(identifier: SubscriptionManager.monthlyPackageID)
217→            ?? offering.package(identifier: "$rc_monthly")
218→            ?? offering.monthly
219→            ?? offering.availablePackages.first(where: { $0.packageType == .monthly })
220→            ?? offering.availablePackages.first(where: { $0.storeProduct.productIdentifier.lowercased().contains("monthly") })
221→    }
222→
223→    var yearlyPackage: Package? {
224→        guard let offering = currentOffering else { return nil }
225→        return offering.package(identifier: SubscriptionManager.yearlyPackageID)
226→            ?? offering.package(identifier: "$rc_annual")
227→            ?? offering.annual
228→            ?? offering.availablePackages.first(where: { $0.packageType == .annual })
229→            ?? offering.availablePackages.first(where: { $0.storeProduct.productIdentifier.lowercased().contains("yearly") || $0.storeProduct.productIdentifier.lowercased().contains("annual") })
230→    }
