232→    @MainActor
233→    private func apply(customerInfo: CustomerInfo) {
234→        self.customerInfo = customerInfo
235→
236→        let previousIsPro = self.isPro
237→        let proIsActive = customerInfo.entitlements
238→            .activeInCurrentEnvironment[SubscriptionManager.grockProEntitlementID] != nil
239→
240→        debugLogEntitlements(customerInfo: customerInfo, proIsActive: proIsActive)
241→
242→        self.isPro = proIsActive
243→        UserDefaults.standard.isPro = proIsActive
244→
245→        if previousIsPro && !proIsActive {
246→            // Always force re-pick of editable stores on every Pro -> Free transition.
247→            UserDefaults.standard.freeEditableStoreKeys = []
248→            UserDefaults.standard.freePrimaryEditableCartId = nil
249→        }
250→
251→        if previousIsPro != proIsActive {
252→            NotificationCenter.default.post(
253→                name: .subscriptionStatusChanged,
254→                object: nil,
255→                userInfo: [
256→                    "isPro": proIsActive,
257→                    "previousIsPro": previousIsPro,
258→                    "changedAt": Date()
259→                ]
260→            )
261→        }
262→    }
