273→    private func beginPurchase() -> Bool {
274→        purchaseLock.lock()
275→        defer { purchaseLock.unlock() }
276→        guard !isPurchaseInProgress else { return false }
277→        isPurchaseInProgress = true
278→        return true
279→    }
280→
281→    private func endPurchase() {
282→        purchaseLock.lock()
283→        isPurchaseInProgress = false
284→        purchaseLock.unlock()
285→    }
