287→    private func ensureStableSandboxAppUserIDIfNeeded() async {
288→        guard isSandboxReceiptBuild else { return }
289→
290→        let targetAppUserID = configuredSandboxAppUserID
291→        let currentAppUserID = Purchases.shared.appUserID
292→        guard currentAppUserID != targetAppUserID else { return }
293→
294→        do {
295→            let result = try await Purchases.shared.logIn(targetAppUserID)
296→            print("ℹ️ [Subscription] Sandbox/TestFlight identity set to \(targetAppUserID). created=\(result.created)")
297→        } catch {
298→            print("⚠️ [Subscription] Failed to set sandbox identity to \(targetAppUserID): \(error.localizedDescription)")
299→        }
300→    }
301→
302→    private var configuredSandboxAppUserID: String {
303→        guard let rawValue = Bundle.main.object(forInfoDictionaryKey: "REVENUECAT_SANDBOX_APP_USER_ID") as? String else {
304→            return Self.fallbackSandboxAppUserID
305→        }
306→
307→        let trimmed = rawValue.trimmingCharacters(in: .whitespacesAndNewlines)
308→        return trimmed.isEmpty ? Self.fallbackSandboxAppUserID : trimmed
309→    }
