315→    private func debugLogEntitlements(customerInfo: CustomerInfo, proIsActive: Bool) {
316→        #if DEBUG
317→        let allEntitlements = customerInfo.entitlements.all.keys.sorted()
318→        let activeEntitlements = customerInfo.entitlements.activeInCurrentEnvironment.keys.sorted()
319→        let snapshot = "all=\(allEntitlements.joined(separator: ","))|active=\(activeEntitlements.joined(separator: ","))|pro=\(proIsActive)|user=\(Purchases.shared.appUserID)"
320→
321→        guard snapshot != lastLoggedEntitlementSnapshot else { return }
322→        lastLoggedEntitlementSnapshot = snapshot
323→
324→        print("ℹ️ [Subscription] Entitlements all=\(allEntitlements) active=\(activeEntitlements) proActive=\(proIsActive) appUserID=\(Purchases.shared.appUserID)")
325→        #endif
326→    }
