import RevenueCat

@MainActor
@Observable
final class GrockPaywallViewModel {
    private let yearlyTrialDays = 7

    var selectedPlan: GrockPaywallPlanCardModel.Plan = .yearly
    var isProcessingAction = false
    var showAlert = false
    var alertMessage = ""

